```javascript
function handleSequelizeError(error) {
  const stackLines = error.stack.split('\n');

  // Regular expression to match the error file format: "at (...filename:line:column)"
  const regex = /\((.*):\d+:\d+\)/;

  for (const line of stackLines) {
    const match = line.match(regex);
    if (match && match[1]) {
      const filename = match[1];
      console.log(`Error occurred in file: ${filename}`);
      break;
    }
  }

  console.error(`Sequelize error: ${error.message}`);
}
```

